 16 | /**
 17 |  * 根据文本和光标位置，计算考虑终端宽度的光标所在的"显示行"
 18 |  * @returns { displayLines, cursorLineIdx, cursorColIdx }
 19 |  */
 20 | function calculateDisplayLines(
 21 |   text: string,
 22 |   cursorOffset: number,
 23 |   terminalWidth: number,
 24 |   promptWidth: number = 2, // '> '
 25 | ) {
 26 |   // 空文本特殊处理
 27 |   if (!text) {
 28 |     return { displayLines: [], cursorLineIdx: -1, cursorColIdx: 0 };
 29 |   }
 30 | 
 31 |   const displayLines: string[] = [];
 32 |   let cursorLineIdx = -1;
 33 |   let cursorColIdx = 0;
 34 |   const availableWidth = Math.max(1, terminalWidth - promptWidth);
 35 |   let accumulatedOffset = 0;
 36 |   let found = false;
 37 | 
 38 |   const lines = text.split('\n');
 39 | 
 40 |   for (let i = 0; i < lines.length; i++) {
 41 |     const line = lines[i];
 42 |     const lineStartOffset = accumulatedOffset;
 43 |     const lineEndOffset = accumulatedOffset + line.length;
 44 | 
 45 |     // 判断光标是否在这一逻辑行内（光标可以在行尾，即紧邻换行符之前）
 46 |     const cursorInThisLine =
 47 |       !found && cursorOffset >= lineStartOffset && cursorOffset <= lineEndOffset;
 48 |     const cursorOffsetInLine = cursorInThisLine ? cursorOffset - lineStartOffset : -1;
 49 | 
 50 |     if (line.length === 0) {
 51 |       // 空行：只产生一行显示
 52 |       displayLines.push('');
 53 |       if (cursorInThisLine && !found) {
 54 |         cursorLineIdx = displayLines.length - 1;
 55 |         cursorColIdx = 0;
 56 |         found = true;
 57 |       }
 58 |     } else {
 59 |       // 对该行进行软换行
 60 |       let offset = 0;
 61 |       while (offset < line.length) {
 62 |         const chunk = line.substring(offset, offset + availableWidth);
 63 |         displayLines.push(chunk);
 64 | 
 65 |         if (cursorInThisLine && !found) {
 66 |           if (cursorOffsetInLine >= offset && cursorOffsetInLine <= offset + chunk.length) {
 67 |             // 光标在这个 chunk 内（或在 chunk 末尾后一个位置，即下一 chunk 开头）
 68 |             cursorLineIdx = displayLines.length - 1;
 69 |             cursorColIdx = Math.min(cursorOffsetInLine - offset, chunk.length);
 70 |             found = true;
 71 |           }
 72 |         }
 73 | 
 74 |         offset += availableWidth;
 75 |       }
 76 |     }
 77 | 
 78 |     accumulatedOffset += line.length + 1; // +1 for newline
 79 |   }
 80 | 
 81 |   // 如果光标位置超出了文本范围，把光标放在最后
 82 |   if (!found) {
 83 |     cursorLineIdx = Math.max(0, displayLines.length - 1);
 84 |     cursorColIdx = displayLines.length > 0 ? displayLines[displayLines.length - 1].length : 0;
 85 |   }
 86 | 
 87 |   return { displayLines, cursorLineIdx, cursorColIdx };
 88 | }
