 90 | export function InputBar({
 91 |   value,
 92 |   cursorOffset,
 93 |   placeholder,
 94 | }: {
 95 |   value: string;
 96 |   cursorOffset: number;
 97 |   placeholder?: string;
 98 | }): React.ReactNode {
 99 |   const { stdout } = useStdout();
100 |   const separator = useMemo(() => '─'.repeat(stdout.columns), [stdout.columns]);
101 |   const status = useSchedulState(inputBarStatusAtom);
102 |   const spinner = useSpinner();
103 | 
104 |   const { displayLines, cursorLineIdx, cursorColIdx } = useMemo(() => {
105 |     return calculateDisplayLines(value, cursorOffset, stdout.columns);
106 |   }, [value, cursorOffset, stdout.columns]);
107 | 
108 |   const cfg = STATUS_CONFIG[status] || STATUS_CONFIG.idle;
109 | 
110 |   return (
111 |     <Box flexDirection="column">
112 |       <Box key="sep-top">
113 |         <Text dimColor>{separator}</Text>
114 |       </Box>
115 |       <Box flexDirection="row" key="input-row">
116 |         <Box key="prompt">
117 |           <Text color={C.primary}>{'>'}</Text>
118 |         </Box>
119 |         <Box flexDirection="column" marginLeft={1} flexGrow={1} key="input-area">
120 |           {displayLines.length === 0 ? (
121 |             <Box key="empty">
122 |               <Text backgroundColor={C.primary}>
123 |                 {' '}
124 |               </Text>
125 |               {placeholder && <Text dimColor>{placeholder}</Text>}
126 |             </Box>
127 |           ) : (
128 |             displayLines.map((line, lineIdx) => {
129 |               const isCursorLine = lineIdx === cursorLineIdx;
130 |               return (
131 |                 <Box key={lineIdx}>
132 |                   {isCursorLine ? (
133 |                     <>
134 |                       {cursorColIdx > 0 ? (
135 |                         <Text>{line.substring(0, cursorColIdx)}</Text>
136 |                       ) : null}
137 |                       <Text backgroundColor={C.primary}>
138 |                         {line[cursorColIdx] || ' '}
139 |                       </Text>
140 |                       {cursorColIdx < line.length ? (
141 |                         <Text>{line.substring(cursorColIdx + 1)}</Text>
142 |                       ) : null}
143 |                     </>
144 |                   ) : (
145 |                     <Text>{line}</Text>
146 |                   )}
147 |                 </Box>
148 |               );
149 |             })
150 |           )}
151 |         </Box>
152 |         {cfg.label && (
153 |           <Box marginLeft={1} key="status-label">
154 |             <Text color={cfg.color}>
155 |               {cfg.spinner ? `${spinner} ${cfg.label}...` : `\u2713 ${cfg.label}`}
156 |             </Text>
157 |           </Box>
158 |         )}
159 |       </Box>
160 |       <Box key="sep-bottom">
161 |         <Text dimColor>{separator}</Text>
162 |       </Box>
163 |     </Box>
164 |   );
165 | }
