  1 | import React from 'react';
  2 | import type { Key } from 'ink';
  3 | import type { InputAction } from '../../data.js';
  4 | import {
  5 |   colOf,
  6 |   rowOf,
  7 |   moveLine,
  8 |   getDisplayLines,
  9 |   displayRowOf,
 10 |   displayColOf,
