 15 | interface UseInputHandlerParams {
 16 |   inputValue: string;
 17 |   cursorOffset: number;
 18 |   showDropdown: boolean;
 19 |   filteredCommands: Array<{ name: string }>;
 20 |   selectedIndex: number;
 21 |   dispatch: React.Dispatch<InputAction>;
 22 |   setSelectedIndex: React.Dispatch<React.SetStateAction<number>>;
 23 |   executeCommand: (name: string, arg?: string) => void;
 24 |   onSubmit?: (text: string) => void;
