 28 | export function useInputHandler({
 29 |   inputValue,
 30 |   cursorOffset,
 31 |   showDropdown,
 32 |   filteredCommands,
 33 |   selectedIndex,
 34 |   dispatch,
 35 |   setSelectedIndex,
 36 |   executeCommand,
 37 |   onSubmit,
 38 |   terminalWidth,
 39 | }: UseInputHandlerParams) {
 40 |   return (_char: string, key: Key) => {
 41 |     // Pre-compute display lines for cursor movement that considers terminal width
 42 |     const displayLines = getDisplayLines(inputValue, terminalWidth);
 43 | 
 44 |     // ── Build context for plugin handlers ──
 45 |     const ctx = {
 46 |       inputValue,
 47 |       cursorOffset,
 48 |       showDropdown,
 49 |       currentRow: rowOf(inputValue, cursorOffset),
 50 |       totalRows: rowOf(inputValue, inputValue.length) + 1,
 51 |       dispatch,
 52 |     };
 53 | 
 54 |     // ── Phase 1: run registered plugin input handlers ──
 55 |     for (const handler of getInputHandlers()) {
 56 |       if (handler(_char, key, ctx)) return;
 57 |     }
 58 | 
 59 |     // ── Phase 2: core input handling ────────────────────
 60 | 
 61 |     // ── Dropdown navigation ──
 62 |     if (showDropdown && filteredCommands.length > 0) {
 63 |       if (key.upArrow) {
 64 |         setSelectedIndex((p) => Math.max(0, p - 1));
 65 |         return;
 66 |       }
 67 |       if (key.downArrow) {
 68 |         setSelectedIndex((p) => Math.min(filteredCommands.length - 1, p + 1));
 69 |         return;
 70 |       }
 71 |     }
 72 | 
 73 |     // ── Multi-line cursor movement (when dropdown not focused) ──
 74 |     if (!showDropdown || filteredCommands.length === 0) {
 75 |       if (key.upArrow) {
 76 |         const curDisplayRow = displayRowOf(cursorOffset, displayLines);
 77 |         if (curDisplayRow > 0) {
 78 |           const currentDl = displayLines[curDisplayRow];
 79 |           const preferredCol = displayColOf(cursorOffset, currentDl);
 80 |           dispatch({
 81 |             type: 'move',
 82 |             cursor: moveDisplayLine(inputValue, cursorOffset, -1, preferredCol, displayLines),
 83 |           });
 84 |           return;
 85 |         }
 86 |         return;
 87 |       }
 88 |       if (key.downArrow) {
 89 |         const curDisplayRow = displayRowOf(cursorOffset, displayLines);
 90 |         if (curDisplayRow < displayLines.length - 1) {
 91 |           const currentDl = displayLines[curDisplayRow];
 92 |           const preferredCol = displayColOf(cursorOffset, currentDl);
 93 |           dispatch({
 94 |             type: 'move',
 95 |             cursor: moveDisplayLine(inputValue, cursorOffset, 1, preferredCol, displayLines),
 96 |           });
 97 |           return;
 98 |         }
 99 |         return;
100 |       }
101 |     }
102 | 
103 |     if (key.leftArrow) {
104 |       dispatch({ type: 'move', cursor: Math.max(0, cursorOffset - 1) });
105 |       return;
106 |     }
107 |     if (key.rightArrow) {
108 |       dispatch({
109 |         type: 'move',
110 |         cursor: Math.min(inputValue.length, cursorOffset + 1),
111 |       });
112 |       return;
113 |     }
114 |     const k = key as Record<string, boolean>;
115 |     if (k.home) {
116 |       const lineStart = inputValue.lastIndexOf('\n', cursorOffset - 1) + 1;
117 |       dispatch({ type: 'move', cursor: lineStart });
118 |       return;
119 |     }
120 |     if (k.end) {
121 |       const lineEnd = inputValue.indexOf('\n', cursorOffset);
122 |       dispatch({
123 |         type: 'move',
124 |         cursor: lineEnd === -1 ? inputValue.length : lineEnd,
125 |       });
126 |       return;
127 |     }
128 | 
129 |     // ── Ctrl+A / Ctrl+E — jump to line start / end ──
130 |     if (key.ctrl && _char === 'a') {
131 |       const lineStart = inputValue.lastIndexOf('\n', cursorOffset - 1) + 1;
132 |       dispatch({ type: 'move', cursor: lineStart });
133 |       return;
134 |     }
135 |     if (key.ctrl && _char === 'e') {
136 |       const lineEnd = inputValue.indexOf('\n', cursorOffset);
137 |       dispatch({
138 |         type: 'move',
139 |         cursor: lineEnd === -1 ? inputValue.length : lineEnd,
140 |       });
141 |       return;
142 |     }
143 | 
144 |     // ── Ctrl+U — clear all, or delete current line if multiline ──
145 |     if (key.ctrl && _char === 'u') {
146 |       if (inputValue.includes('\n')) {
147 |         const lineStart = inputValue.lastIndexOf('\n', cursorOffset - 1) + 1;
148 |         const lineEnd = inputValue.indexOf('\n', cursorOffset);
149 |         const isLastLine = lineEnd === -1;
150 |         const end = isLastLine ? inputValue.length : lineEnd;
151 |         dispatch({ type: 'clear' });
152 |         dispatch({
153 |           type: 'insert',
154 |           text: inputValue.slice(0, lineStart) + (isLastLine ? '' : inputValue.slice(end + 1)),
155 |         });
156 |         dispatch({ type: 'move', cursor: lineStart });
157 |       } else {
158 |         dispatch({ type: 'clear' });
159 |       }
160 |       return;
161 |     }
162 | 
163 |     // ── Regular Enter ──
164 |     if (key.return) {
165 |       // Backslash + Enter — remove backslash, insert newline (universal)
166 |       if (cursorOffset > 0 && inputValue[cursorOffset - 1] === '\\') {
167 |         dispatch({ type: 'backspace' });
168 |         dispatch({ type: 'insert', text: '\n' });
169 |         return;
170 |       }
171 |       // Shift+Enter (CSI u) / Option+Enter — insert newline
172 |       if (key.shift || key.meta) {
173 |         dispatch({ type: 'insert', text: '\n' });
174 |         return;
175 |       }
176 |       const text = inputValue.trim();
177 |       if (!text) return;
178 | 
179 |       if (showDropdown && filteredCommands.length > 0) {
180 |         const cmd = filteredCommands[selectedIndex];
181 |         dispatch({ type: 'clear' });
182 |         executeCommand(cmd.name);
183 |         return;
184 |       }
185 | 
186 |       dispatch({ type: 'clear' });
187 | 
188 |       // If input starts with /, treat as a command
189 |       if (text.startsWith('/')) {
190 |         const cmdText = text.slice(1);
191 |         const spaceIdx = cmdText.indexOf(' ');
192 |         const cmdName = spaceIdx >= 0 ? cmdText.slice(0, spaceIdx) : cmdText;
193 |         const cmdArg = spaceIdx >= 0 ? cmdText.slice(spaceIdx + 1).trim() : undefined;
194 |         executeCommand(cmdName, cmdArg);
195 |         return;
196 |       }
197 | 
198 |       onSubmit?.(text);
199 |       return;
200 |     }
201 | 
202 |     // ── Terminal-configured Shift+Enter (VS Code / iTerm2 sends ESC \r) ──
203 |     if (_char === '\r') {
204 |       dispatch({ type: 'insert', text: '\n' });
205 |       return;
206 |     }
207 | 
208 |     // ── Backspace / Delete — deletes char before cursor ──
209 |     if (key.backspace || key.delete) {
210 |       dispatch({ type: 'backspace' });
211 |       if (showDropdown) setSelectedIndex(0);
212 |       return;
213 |     }
214 | 
215 |     // ── Regular character input (incl. IME multi-byte) ──
216 |     if (!key.ctrl && !key.meta && _char) {
217 |       const cp = _char.charCodeAt(0);
218 |       if (_char.length > 1 || cp >= 32) {
219 |         dispatch({ type: 'insert', text: _char });
220 |         if (showDropdown) setSelectedIndex(0);
221 |         return;
222 |       }
223 |     }
224 |   };
225 | }
