  1 | /** Get the visual column (0-based) of cursor in a multi-line string */
  2 | export function colOf(text: string, offset: number): number {
  3 |   const lineStart = text.lastIndexOf('\n', offset - 1) + 1;
  4 |   return offset - lineStart;
  5 | }
