  7 | /** Get line index (0-based) of cursor */
  8 | export function rowOf(text: string, offset: number): number {
  9 |   let r = 0;
 10 |   for (let i = 0; i < offset; i++) {
 11 |     if (text[i] === '\n') r++;
 12 |   }
 13 |   return r;
 14 | }
 15 | 
 16 | /** Move cursor up/down by `dir` lines (±1), trying to keep visual column */
 17 | export function moveLine(text: string, offset: number, dir: 1 | -1, preferredCol: number): number {
 18 |   const curRow = rowOf(text, offset);
 19 |   const targetRow = curRow + dir;
 20 |   if (targetRow < 0) return 0;
 21 |   if (targetRow > rowOf(text, text.length)) return text.length;
 22 | 
 23 |   let r = 0;
 24 |   let targetStart = 0;
 25 |   for (let i = 0; i <= text.length; i++) {
 26 |     if (r === targetRow) {
 27 |       targetStart = i;
 28 |       break;
 29 |     }
 30 |     if (text[i] === '\n') r++;
 31 |   }
 32 | 
 33 |   let targetEnd = text.indexOf('\n', targetStart);
 34 |   if (targetEnd === -1) targetEnd = text.length;
 35 | 
 36 |   return Math.min(targetStart + preferredCol, targetEnd);
 37 | }
