 39 | // ── Display-line-aware versions (consider terminal width / word wrap) ──
 40 | 
 41 | /**
 42 |  * Given the full text, terminal width, and prompt width, split the text into
 43 |  * display lines (logical lines broken by both '\n' and soft wrap).
 44 |  * Returns the list of start offsets (into `text`) for each display line,
 45 |  * and the length of each display line (as a substring).
 46 |  */
 47 | export interface DisplayLineInfo {
 48 |   /** Absolute start offset in `text` where this display line begins */
 49 |   startOffset: number;
 50 |   /** Length (number of characters) of this display line in `text` */
 51 |   length: number;
 52 | }
 53 | 
 54 | export function getDisplayLines(
 55 |   text: string,
 56 |   terminalWidth: number,
 57 |   promptWidth: number = 2,
 58 | ): DisplayLineInfo[] {
 59 |   const avail = Math.max(1, terminalWidth - promptWidth);
 60 |   const result: DisplayLineInfo[] = [];
 61 | 
 62 |   const logicalLines = text.split('\n');
 63 |   let absOffset = 0;
 64 | 
 65 |   for (const logicalLine of logicalLines) {
 66 |     if (logicalLine.length === 0) {
 67 |       result.push({ startOffset: absOffset, length: 0 });
 68 |     } else {
 69 |       let offset = 0;
 70 |       while (offset < logicalLine.length) {
 71 |         const chunkLen = Math.min(avail, logicalLine.length - offset);
 72 |         result.push({ startOffset: absOffset + offset, length: chunkLen });
 73 |         offset += chunkLen;
 74 |       }
 75 |     }
 76 |     absOffset += logicalLine.length + 1; // +1 for '\n'
 77 |   }
 78 | 
 79 |   return result;
 80 | }
 81 | 
 82 | /**
 83 |  * Given a cursor offset in text, return its display-line index (0-based)
 84 |  * within the displayLines computed by `getDisplayLines`.
 85 |  */
 86 | export function displayRowOf(
 87 |   cursorOffset: number,
 88 |   displayLines: DisplayLineInfo[],
 89 | ): number {
 90 |   for (let i = displayLines.length - 1; i >= 0; i--) {
 91 |     const dl = displayLines[i];
 92 |     if (cursorOffset >= dl.startOffset && cursorOffset <= dl.startOffset + dl.length) {
 93 |       return i;
 94 |     }
 95 |   }
 96 |   return Math.max(0, displayLines.length - 1);
 97 | }
 98 | 
 99 | /**
100 |  * Given a cursor offset in text, return its display-line column (0-based).
101 |  */
102 | export function displayColOf(
103 |   cursorOffset: number,
104 |   dl: DisplayLineInfo,
105 | ): number {
106 |   return Math.max(0, cursorOffset - dl.startOffset);
107 | }
108 | 
109 | /**
110 |  * Move cursor up/down by `dir` display lines (±1), preserving preferred
111 |  * display column.  Uses displayLines (which accounts for terminal width).
112 |  * Returns the new cursor offset into `text`.
113 |  */
114 | export function moveDisplayLine(
115 |   text: string,
116 |   cursorOffset: number,
117 |   dir: 1 | -1,
118 |   preferredCol: number,
119 |   displayLines: DisplayLineInfo[],
120 | ): number {
121 |   if (displayLines.length === 0) return 0;
122 | 
123 |   const curDisplayRow = displayRowOf(cursorOffset, displayLines);
124 |   const targetRow = curDisplayRow + dir;
125 | 
126 |   // Clamp to valid range
127 |   if (targetRow < 0) return 0;
128 |   if (targetRow >= displayLines.length) return text.length;
129 | 
130 |   const targetLine = displayLines[targetRow];
131 |   // Cap the column at the end of the target display line
132 |   const col = Math.min(preferredCol, targetLine.length);
133 |   return targetLine.startOffset + col;
134 | }
